const raw = $input.all().map(i => i.json);
const businesses = raw.length === 1 && Array.isArray(raw[0]) ? raw[0] : raw;
const results = [];
for (const biz of businesses) {
  const id = biz.business_id || biz.name;
  if (!id || id === '_template') continue;
  results.push({ json: {
    businessId: id,
    businessName: biz.name || id,
    businessPath: 'memory-bank/businesses/' + id,
    repo_name: biz.repo_name || id,
    site_url: biz.site_url || '',
    category: biz.category || '',
    tagline: biz.tagline || ''
  }});
}
if (results.length === 0) results.push({ json: { businessId: 'bayflow', businessName: 'BayFlow', businessPath: 'memory-bank/businesses/bayflow', repo_name: 'bayflow', site_url: 'https://bayflow.app', category: 'auto_repair', tagline: '' } });
return results;

// Find the latest app-test, competitor, and seo report filenames from the directory listing
const files = $('List Reports Directory').first().json;
const fileList = Array.isArray(files) ? files : (files.body ? JSON.parse(files.body) : []);

let latestAppTest = '';
let latestCompetitor = '';
let latestSeo = '';

const nameList = Array.isArray(fileList) ? fileList.map(f => f.name || f) : [];

for (const name of nameList) {
  if (typeof name === 'string') {
    if (name.startsWith('app-test-') && name > latestAppTest) latestAppTest = name;
    if (name.startsWith('competitor-') && name > latestCompetitor) latestCompetitor = name;
    if (name.startsWith('seo-') && name > latestSeo) latestSeo = name;
  }
}

return [{
  json: {
    latestAppTest,
    latestCompetitor,
    latestSeo
  }
}];

// Gather all data sources
const biz = $('Split Into Businesses').item.json;
const businessId = biz.businessId;
const businessName = biz.businessName;
const businessPath = biz.businessPath;
const category = biz.category;

const systemContext = (() => {
  try {
    const raw = $('Read System Context (Supabase)').first().json;
    return typeof raw === 'string' ? raw : JSON.stringify(raw, null, 2);
  } catch (e) { return 'System context unavailable: ' + e.message; }
})();

const prd = (() => {
  try { return $('Read PRD').first().json.content || 'PRD not found.'; }
  catch (e) { return 'PRD unavailable: ' + e.message; }
})();

const state = (() => {
  try { return $('Read State').first().json.content || ''; }
  catch (e) { return 'State unavailable: ' + e.message; }
})();

const plan = (() => {
  try { return $('Read Weekly Plan').first().json.content || ''; }
  catch (e) { return 'Weekly plan unavailable: ' + e.message; }
})();

const supportLog = (() => {
  try { return $('Read Support Log').first().json.content || 'No support tickets yet.'; }
  catch (e) { return 'Support log unavailable: ' + e.message; }
})();

const appTestReport = (() => {
  try {
    const raw = $('Read App Test Report').first().json;
    return typeof raw === 'string' ? raw : (raw.data || JSON.stringify(raw, null, 2));
  } catch (e) { return 'App test report unavailable: ' + e.message; }
})();

const competitorReport = (() => {
  try {
    const raw = $('Read Competitor Report').first().json;
    return typeof raw === 'string' ? raw : (raw.data || JSON.stringify(raw, null, 2));
  } catch (e) { return 'Competitor report unavailable: ' + e.message; }
})();

const seoReport = (() => {
  try {
    const raw = $('Read SEO Report').first().json;
    return typeof raw === 'string' ? raw : (raw.data || JSON.stringify(raw, null, 2));
  } catch (e) { return 'SEO report unavailable: ' + e.message; }
})();

const today = $now.toFormat('yyyy-MM-dd');

return [{
  json: {
    businessId,
    businessName,
    businessPath,
    repo_name: biz.repo_name,
    prompt: `Today is ${today}. You are the Product Agent for ${businessName} (${category || 'SaaS'} software by Forge Technologies).

You have access to REAL data from multiple sources. Your job is to analyze all of it and produce highly specific, actionable GitHub issues.

---

## 1. PRD (Product Requirements Document) — What Was Supposed To Be Built
${prd}

---

## 2. Current State
${state}

---

## 3. Weekly Plan
${plan}

---

## 4. System Context — Real Metrics (Traffic, Revenue, Signups, Churn)
${systemContext}

---

## 5. Recent Support Tickets
${supportLog}

---

## 6. Latest App Test Report — What's Broken
${appTestReport}

---

## 7. Latest Competitor Report — What Competitors Have
${competitorReport}

---

## 8. Latest SEO Report — Keyword Performance
${seoReport}

---

# YOUR ANALYSIS TASKS

Perform ALL of the following analyses. Be specific, cite data, and reference exact PRD sections.

## Analysis 1: PRD vs Reality Gap
Compare the PRD against the current state and app test report. For each PRD feature/section:
- Is it built? Partially built? Not started?
- If built, does it pass tests or is it broken?
- Rank the gaps by revenue impact.

## Analysis 2: Support Ticket Themes
Group support tickets by theme. For each theme:
- Count of tickets
- Example ticket text
- Root cause hypothesis
- Suggested fix

## Analysis 3: App Test Failures
For each failing test or broken feature from the app test report:
- What exactly is broken
- How to reproduce
- Severity (blocks usage, degrades experience, cosmetic)

## Analysis 4: Usage Data Analysis
From the system_context metrics:
- Which features have high usage? Low usage? Zero usage?
- Signup-to-activation funnel: where are users dropping off?
- Revenue trends: growing, flat, declining?
- Churn indicators: what correlates with churn?

## Analysis 5: Competitive Gap Analysis
From the competitor report:
- What do competitors offer that we don't?
- Which competitor features appear in our support tickets (users asking for them)?
- Which competitor features would most impact retention if we added them?

## Analysis 6: SEO Performance
From the SEO report:
- Which keywords are ranking? Which are declining?
- Any technical SEO issues (broken links, missing meta, sitemap)?
- Content gaps: keywords competitors rank for that we don't?

## Analysis 7: Prioritized Issue List
Combine all analyses into a single prioritized list. Rank by:
- P0: Blocks revenue (broken payment, signup, core feature)
- P1: Affects retention (features users need, UX confusion, missing competitor parity)
- P2: Nice to have (SEO improvements, minor UX polish, features with low demand)

---

# OUTPUT FORMAT

First, output a brief executive summary (5-10 lines max) with:
- Overall status: GREEN / YELLOW / RED
- Key metric changes since last week
- Top 3 priorities this week

Then output your full analysis for each of the 7 sections above.

Finally, output a section called ## GitHub Issues

For EACH actionable item (aim for 5-15 issues, quality over quantity), output:

### Issue: @claude [Product] <Clear descriptive title>
**Priority:** P0 / P1 / P2
**User Story:** As a [role], I want to [action] so that [benefit].
**PRD Reference:** [Section X.Y if applicable, or "N/A"]
**Acceptance Criteria:**
- [ ] Criterion 1
- [ ] Criterion 2
- [ ] Criterion 3
**Context:** [Why this matters now — cite specific data: support ticket count, test failure, competitor feature, usage metric, etc.]

Do NOT output vague issues like "improve performance" or "fix bugs". Every issue must reference specific data from the inputs above.`
  }
}];

const response = $json.text;
const businessId = $('Build Product Prompt').first().json.businessId;
const businessName = $('Build Product Prompt').first().json.businessName;
const businessPath = $('Build Product Prompt').first().json.businessPath;
const repo_name = $('Build Product Prompt').first().json.repo_name;

// Extract GitHub issues from the response — updated regex to match new format
const issueRegex = /### Issue: (.+?)\n([\s\S]*?)(?=### Issue:|## |$)/g;
const issues = [];
let match;
while ((match = issueRegex.exec(response)) !== null) {
  const title = match[1].trim();
  const body = match[2].trim();

  // Extract priority from body
  const priorityMatch = body.match(/\*\*Priority:\*\*\s*(P[012])/);
  const priority = priorityMatch ? priorityMatch[1] : 'P2';

  issues.push({ title, body, priority });
}

// Sort: P0 first, then P1, then P2
const priorityOrder = { 'P0': 0, 'P1': 1, 'P2': 2 };
issues.sort((a, b) => (priorityOrder[a.priority] || 3) - (priorityOrder[b.priority] || 3));

return [{
  json: {
    report: response,
    issues,
    issueCount: issues.length,
    p0Count: issues.filter(i => i.priority === 'P0').length,
    p1Count: issues.filter(i => i.priority === 'P1').length,
    p2Count: issues.filter(i => i.priority === 'P2').length,
    businessId,
    businessName,
    businessPath,
    repo_name
  }
}];

// Create GitHub issues in the business app repo for Claude Code to pick up
const issues = $('Parse GitHub Issues').first().json.issues;
const repo_name = $('Parse GitHub Issues').first().json.repo_name;
if (!issues || issues.length === 0) {
  return [{ json: { message: 'No issues to create', repo_name } }];
}

const today = $now.toFormat('yyyy-MM-dd');

// Map priority to GitHub labels
const priorityLabels = {
  'P0': 'priority-p0',
  'P1': 'priority-p1',
  'P2': 'priority-p2'
};

return issues.map(issue => ({
  json: {
    title: issue.title.startsWith('@claude') ? issue.title : `@claude [Product] ${issue.title}`,
    body: `${issue.body}\n\n---\n_Auto-generated by Product Agent on ${today} | Priority: ${issue.priority}_`,
    labels: `product-agent,${priorityLabels[issue.priority] || 'priority-p2'}`,
    repo_name
  }
}));
